"-- Enumeration for different types of content managed on the site\nCREATE TYPE content_type_enum AS ENUM (\n    'blog_post',\n    'book',\n    'podcast_episode',\n    'service_page',\n    'static_page',\n    'media_item'\n);\n\n-- Table for storing contact form submissions\nCREATE TABLE contact_submissions (\n    id SERIAL PRIMARY KEY,\n    first_name VARCHAR(100) NOT NULL,\n    last_name VARCHAR(100) NOT NULL,\n    email VARCHAR(255) NOT NULL,\n    message TEXT NOT NULL,\n    submitted_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for managing various content items (Blog Posts, Books, Podcasts, Service Pages, etc.)\nCREATE TABLE content_items (\n    id SERIAL PRIMARY KEY,\n    title VARCHAR(255) NOT NULL,\n    slug VARCHAR(255) UNIQUE NOT NULL, -- URL-friendly identifier\n    content_type content_type_enum NOT NULL,\n    short_description TEXT,\n    full_content TEXT, -- Markdown or HTML content\n    featured_image_url VARCHAR(255),\n    seo_title VARCHAR(255),\n    seo_description TEXT,\n    published_at TIMESTAMP WITH TIME ZONE,\n    updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n    is_published BOOLEAN DEFAULT TRUE,\n    author_id INTEGER, -- Foreign key to the 'users' table\n    metadata JSONB DEFAULT '{}'\n);\n\n-- Table for client testimonials\nCREATE TABLE testimonials (\n    id SERIAL PRIMARY KEY,\n    client_name VARCHAR(255) NOT NULL,\n    client_title_company VARCHAR(255),\n    quote TEXT NOT NULL,\n    client_image_url VARCHAR(255),\n    display_order INTEGER DEFAULT 0,\n    is_active BOOLEAN DEFAULT TRUE,\n    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for team members\nCREATE TABLE team_members (\n    id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    title VARCHAR(255),\n    bio TEXT,\n    profile_image_url VARCHAR(255),\n    linkedin_url VARCHAR(255),\n    display_order INTEGER DEFAULT 0,\n    is_active BOOLEAN DEFAULT TRUE,\n    created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Table for
